import React from 'https://cdn.jsdelivr.net/npm/react@19/+esm';
import { createRoot } from 'https://cdn.jsdelivr.net/npm/react-dom@19/client/+esm';
import Isoflow from 'https://cdn.jsdelivr.net/npm/fossflow@1.0.5/+esm';
const el = document.createElement('div'); el.style.height = '400px'; shadowRoot.appendChild(el);
createRoot(el).render(React.createElement(Isoflow, { initialData: { ...data.model, fitToView: true }, editorMode: 'EXPLORABLE_READONLY', width: '100%', height: 400 }));

